$(document).ready(function ($) {
                $.ajaxSetup({
                    headers: {
                        'X-CSRF-TOKEN': $('meta[name="csrf-token"]').attr('content')
                    }
                });

                $(document).on('click', '.reporta_mejora', function () {
                    $('#bug-report-button-origin-id').val($(this).attr('id'));
                    $('#bug-report-modal').addClass('show');
                });

                $(document).on('click', '#send-report-action', function () {
                    $("#bug-report-modal").removeClass('show');

                    const comment = $('#bug-report-comments').val().trim();
                    if (comment === '') {
                        $('#bug-report-comments').val('')
                        return;
                    }
                    let reportaMejoraButton = $('#' + $('#bug-report-button-origin-id').val());

                    let content = {
                        wp_id: 346755,
                        origin: reportaMejoraButton.data("origin"),
                        perm: reportaMejoraButton.data("perm"),

                        topic_id: reportaMejoraButton.data("topic_id"),
                        topic_title: reportaMejoraButton.data("topic_title"),
                        topic_chapter: reportaMejoraButton.data("topic_chapter"),
                        perm_url_name: reportaMejoraButton.data("perm_url_name"),

                        questionary_id: reportaMejoraButton.data("questionary_id"),
                        questionary_title: reportaMejoraButton.data("questionary_title"),
                        questionary_number_name: reportaMejoraButton.data("questionary_number_name"),
                        questionary_type: reportaMejoraButton.data("questionary_type"),
                        question_id: reportaMejoraButton.data("question_id"),
                        question_position: reportaMejoraButton.data("question_position"),

                        comment: comment,
                    };

                    $.ajax({
                        method: 'post',
                        url: 'https://teorica.practicavial.com/api/v1/bug-report',
                        dataType: 'json',
                        data: content,
                        success: function () {
                            $('#bug-report-comments').val('')
                            $('#bug-report-result-modal').addClass('show');
                        },
                        error: function () {
                            $('#bug-report-comments').val('')
                            $('#bug-report-result-error-modal').addClass('show');
                        }
                    });
                });
            });

